import{_ as e,o as a,c as r,Q as t}from"./chunks/framework.6d94f49f.js";const _=JSON.parse('{"title":"k8s网络插件","description":"","frontmatter":{},"headers":[],"relativePath":"DevOps/Kubernetes/网络/k8s网络插件.md","filePath":"DevOps/Kubernetes/网络/k8s网络插件.md","lastUpdated":1701334216000}'),n={name:"DevOps/Kubernetes/网络/k8s网络插件.md"},s=t('<h1 id="k8s网络插件" tabindex="-1">k8s网络插件 <a class="header-anchor" href="#k8s网络插件" aria-label="Permalink to &quot;k8s网络插件&quot;">​</a></h1><ul><li><a href="https://developer.aliyun.com/article/1245323" target="_blank" rel="noreferrer">参考网站</a></li></ul><h1 id="cni-网络插件" tabindex="-1">CNI 网络插件 <a class="header-anchor" href="#cni-网络插件" aria-label="Permalink to &quot;CNI 网络插件&quot;">​</a></h1><ul><li><a href="https://github.com/containernetworking/cni?spm=a2c6h.12873639.article-detail.8.37087419OM1oKj" target="_blank" rel="noreferrer">CNI</a></li></ul><h4 id="什么是-cni" tabindex="-1">什么是 CNI？ <a class="header-anchor" href="#什么是-cni" aria-label="Permalink to &quot;什么是 CNI？&quot;">​</a></h4><p>CNI（容器网络接口）是一个云原生计算基金会项目，它包含了一些规范和库，用于编写在 Linux 容器中配置网络接口的一系列插件。CNI 只关注容器的网络连接，并在容器被删除时移除所分配的资源。 Kubernetes 使用 CNI 作为网络提供商和 Kubernetes Pod 网络之间的接口。</p><h4 id="cni-使用了哪些网络模型" tabindex="-1">CNI 使用了哪些网络模型？ <a class="header-anchor" href="#cni-使用了哪些网络模型" aria-label="Permalink to &quot;CNI 使用了哪些网络模型？&quot;">​</a></h4><p>CNI 网络插件使用封装网络模型（例如 Virtual Extensible Lan，缩写是 VXLAN）或非封装网络模型（例如 Border Gateway Protocol，缩写是 BGP）来实现网络结构。</p><p>路由分发：一种外部网关协议，用于在互联网上交换路由和可达性信息。BGP 可以帮助进行跨集群 pod 之间的网络。此功能对于未封装的 CNI 网络插件是必须的，并且通常由 BGP 完成。如果你想构建跨网段拆分的集群，路由分发是一个很好的功能。</p><p>网络策略：Kubernetes 提供了强制执行规则的功能，这些规则决定了哪些 service 可以使用网络策略进行相互通信。这是从 Kubernetes 1.7 起稳定的功能，可以与某些网络插件一起使用。</p><p>网格：允许在不同的 Kubernetes 集群间进行 service 之间的网络通信。 外部数据存储：具有此功能的 CNI 网络插件需要一个外部数据存储来存储数据。</p><p>加密：允许加密和安全的网络控制和数据平面。 Ingress/Egress 策略：允许你管理 Kubernetes 和非 Kubernetes 通信的路由控制。</p><h4 id="什么是封装网络" tabindex="-1">什么是封装网络？ <a class="header-anchor" href="#什么是封装网络" aria-label="Permalink to &quot;什么是封装网络？&quot;">​</a></h4><p>此网络模型提供了一个逻辑二层（L2）网络，该网络封装在跨 Kubernetes 集群节点的现有三层（L3）网络拓扑上。使用此模型，你可以为容器提供一个隔离的 L2 网络，而无需分发路由。封装网络带来了少量的处理开销以及由于覆盖封装生成 IP header 造成的 IP 包大小增加。封装信息由 Kubernetes worker 之间的 UDP 端口分发，交换如何访问 MAC 地址的网络控制平面信息。此类网络模型中常用的封装是 VXLAN、Internet 协议安全性 (IPSec) 和 IP-in-IP。 简单来说，这种网络模型在 Kubernetes worker 之间生成了一种扩展网桥，其中连接了 pod。 如果你偏向使用扩展 L2 网桥，则可以选择此网络模型。此网络模型对 Kubernetes worker 的 L3 网络延迟很敏感。如果数据中心位于不同的地理位置，请确保它们之间的延迟较低，以避免最终的网络分段。 使用这种网络模型的 CNI 网络插件包括 Flannel、Canal、Weave 和 Cilium。默认情况下，Calico 不会使用此模型，但你可以对其进行配置。</p><h4 id="什么是非封装网络" tabindex="-1">什么是非封装网络？ <a class="header-anchor" href="#什么是非封装网络" aria-label="Permalink to &quot;什么是非封装网络？&quot;">​</a></h4><p>该网络模型提供了一个 L3 网络，用于在容器之间路由数据包。此模型不会生成隔离的 L2 网络，也不会产生开销。这些好处的代价是，Kubernetes worker 必须管理所需的所有路由分发。该网络模型不使用 IP header 进行封装，而是使用 Kubernetes Worker 之间的网络协议来分发路由信息以实现 Pod 连接，例如 BGP。 简而言之，这种网络模型在 Kubernetes worker 之间生成了一种扩展网络路由器，提供了如何连接 Pod 的信息。 如果你偏向使用 L3 网络，则可以选择此网络模型。此模型在操作系统级别为 Kubernetes Worker 动态更新路由。对延迟较不敏感。 使用这种网络模型的 CNI 网络插件包括 Calico 和 Cilium。Cilium 可以使用此模型进行配置，即使这不是默认模式。</p>',16),o=[s];function i(l,c,u,h,d,p){return a(),r("div",null,o)}const k=e(n,[["render",i]]);export{_ as __pageData,k as default};
